# ------------------------------------------------------------------
# Graph nodes
# ------------------------------------------------------------------
def _nodes() -> list:
    return [
        helper.make_node('MatMul', inputs=['model_input', 'n0_mm4d_w'], outputs=['n0_mm4d_out']),
        helper.make_node('Conv', inputs=['n0_mm4d_out', 'n100_conv_w', 'n100_conv_b'], outputs=['n100_conv_cv'], kernel_shape=[3, 3], pads=[1, 1, 1, 1]),
        helper.make_node('Mul', inputs=['n100_conv_cv', 'n100_conv_alpha'], outputs=['n100_conv_mu']),
        helper.make_node('Add', inputs=['n100_conv_mu', 'n100_conv_beta'], outputs=['n100_conv_ad']),
        helper.make_node('Clip', inputs=['n100_conv_ad', 'n100_conv_zero', 'n100_conv_one'], outputs=['n100_conv_out']),
        helper.make_node('Resize', inputs=['n100_conv_out', 'n200_resi_roi', 'n200_resi_scales'], outputs=['n200_resi_out'], coordinate_transformation_mode='asymmetric', mode='linear'),
        helper.make_node('Conv', inputs=['n200_resi_out', 'n300_cba_wm', 'n300_cba_bm'], outputs=['n300_cba_main'], kernel_shape=[3, 3], pads=[1, 1, 1, 1], strides=[1, 1]),
        helper.make_node('Relu', inputs=['n300_cba_main'], outputs=['n300_cba_relum']),
        helper.make_node('Conv', inputs=['n200_resi_out', 'n300_cba_ws', 'n300_cba_bs'], outputs=['n300_cba_skip'], kernel_shape=[1, 1], pads=[0, 0, 0, 0], strides=[1, 1]),
        helper.make_node('Add', inputs=['n300_cba_relum', 'n300_cba_skip'], outputs=['n300_cba_out']),
        helper.make_node('MaxPool', inputs=['n300_cba_out'], outputs=['n400_mpd_out'], dilations=[2, 2], kernel_shape=[3, 3], pads=[1, 1, 1, 1], strides=[1, 1]),
    ]

# ------------------------------------------------------------------
# Model builder
# ------------------------------------------------------------------
def build_model() -> bytes:
    inputs_info  = [helper.make_tensor_value_info(INPUT_NAME, TensorProto.FLOAT, INPUT_SHAPE)]
    outputs_info = [helper.make_tensor_value_info(OUTPUT_NAME, TensorProto.FLOAT, OUTPUT_SHAPE)]
    graph = helper.make_graph(_nodes(), "bug_000227", inputs_info, outputs_info, initializer=_inits())
    model = helper.make_model(graph, opset_imports=[helper.make_opsetid("", OPSET)])
    model.ir_version = IR_VERSION
    return model.SerializeToString()


